export function LandingLogo(
  props: Omit<React.ComponentProps<typeof Link>, 'href'>,
) {
  return (
    <Link
      href="/"
      {...props}
      className={cn(
        'inline-flex items-center gap-3 font-semibold text-fd-foreground',
        props.className,
      )}
    >
      <LogoMark />
    </Link>
  );
}

export const landingLinks: LinkItemType[] = [
  {
    type: 'menu',
    text: 'Conteúdo',
    on: 'all',
    items: [
      { text: 'Episódios', url: '/episodios' },
      { text: 'Guia do Ouvinte', url: '/docs' },
    ],
  },
  { text: 'Dashboard', url: '/dashboard/home', on: 'all' },
];

export function LandingHeader() {
  const projectMenu = landingLinks.find(
    (item) => item.type === 'menu' && item.text === 'Conteúdo',
  );
  const dashboardItem = landingLinks.find(
    (item) => item.type !== 'menu' && 'url' in item && item.text === 'Dashboard',
  );
  const menuItems = landingLinks.filter((item) =>
    ['menu', 'all'].includes(item.on ?? 'all'),
  );

  return (
    <Navbar>
      <LandingLogo className="inline-flex items-center gap-3 font-semibold" />

      <div className="hidden flex-1 items-center justify-center gap-3 px-6 md:flex">
        {projectMenu && projectMenu.type === 'menu' ? (
          <NavbarMenu>
            <NavbarMenuTrigger className="rounded-full px-4 py-2 text-sm text-fd-muted-foreground transition-colors hover:text-fd-foreground [&_svg]:hidden">
              {projectMenu.text}
            </NavbarMenuTrigger>
            <NavbarMenuContent className="grid min-w-[540px] gap-2 p-2 md:grid-cols-2">
              {projectMenu.items.filter(hasUrlMenuItem).map((item, i) => (
                <NavbarMenuLink
                  key={i}
                  href={item.url}
                  external={item.external}
                >
                  <p className="text-sm font-medium text-fd-foreground">{item.text}</p>
                  <p className="text-sm text-fd-muted-foreground">
                    {navbarDescriptions[String(item.text)] ?? 'Abrir esta seção do projeto.'}
                  </p>
                </NavbarMenuLink>
              ))}
            </NavbarMenuContent>
          </NavbarMenu>
        ) : null}

        {dashboardItem && dashboardItem.type !== 'menu' && 'url' in dashboardItem ? (
          <Link
            href={dashboardItem.url}
            className="rounded-full px-4 py-2 text-sm text-fd-muted-foreground transition-colors hover:text-fd-foreground"
          >
            {dashboardItem.text}
          </Link>
        ) : null}
      </div>

      <div className="hidden flex-1 items-center justify-end gap-1.5 md:flex">
        <LargeSearchToggle
          className="w-full max-w-[240px] rounded-full ps-2.5"
          hideIfDisabled
        />
        <ThemeToggle mode="light-dark" />
      </div>

      <div className="ms-auto flex flex-row items-center md:hidden">
        <SearchToggle className="p-2" hideIfDisabled />
        <Menu>
          <MenuTrigger
            aria-label="Toggle Menu"
            className={cn(
              buttonVariants({
                size: 'icon',
                color: 'ghost',
                className: 'group',
              }),
            )}
          >
            <ChevronDown className="!size-5.5 transition-transform duration-300 group-data-[state=open]:rotate-180" />
          </MenuTrigger>
          <MenuContent>
            {menuItems.map((item, i) => (
              <MenuLinkItem key={i} item={item} />
            ))}
          </MenuContent>
        </Menu>
      </div>
    </Navbar>
  );
}

function hasUrlMenuItem(
  item: NonNullable<Extract<LinkItemType, { type: 'menu' }>['items']>[number],
): item is Extract<
  NonNullable<Extract<LinkItemType, { type: 'menu' }>['items']>[number],
  { url: string }
> {
  return 'url' in item && typeof item.url === 'string';
}

const navbarDescriptions: Record<string, string> = {
  Hero: 'Bloco principal de apresentação.',
  'Guia do Ouvinte': 'Como participar e ouvir nosso conteúdo.',
  Eixos: 'Veja os três pilares tecnológicos do trabalho.',
  Episódios: 'Confira os conteúdos e formatos planejados.',
  Equipe: 'Organização do grupo e frentes do projeto.',
  Cronograma: 'Resumo das etapas para a entrega final.',
  Faculdade: 'Site institucional da Serra Dourada Lorena.',
};

export function LandingFooter() {
  return (
    <footer className="border-t border-fd-border bg-fd-card text-fd-foreground">
      <div className="mx-auto flex w-full max-w-[1100px] flex-col gap-8 px-4 py-10 sm:px-6 md:flex-row md:items-end md:justify-between">
        <div className="max-w-xl">
          <p className="text-sm font-semibold uppercase tracking-[0.18em] text-fd-muted-foreground">
            PodcastADS
          </p>
          <p className="mt-3 text-sm leading-6 text-fd-muted-foreground">
            Portal do projeto acadêmico desenvolvido para a Faculdade Serra
            Dourada Lorena, com área pública de apresentação e painel interno
            para operação.
          </p>
        </div>

        <div className="flex flex-wrap gap-4 text-sm text-fd-muted-foreground">
          <Link href="/dashboard/home" className="hover:text-fd-foreground">
            Dashboard
          </Link>
          <a
            href="https://serradouradalorena.com.br"
            target="_blank"
            rel="noreferrer"
            className="hover:text-fd-foreground"
          >
            Faculdade Serra Dourada
          </a>
        </div>
      </div>
    </footer>
  );
}
